```go
// 클라이언트: 파일 청크 전송
stream, err := client.UploadFile(ctx)

file, _ := os.Open("large_file.bin")
defer file.Close()

for {
    buf := make([]byte, 64*1024)  // 64KB 청크
    n, err := file.Read(buf)
    if err == io.EOF {
        break
    }
    stream.Send(&FileChunk{
        Filename: "large_file.bin",
        Data: buf[:n],
    })
}

response, err := stream.CloseAndRecv()

// 서버: 청크 수신 및 조합
